import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {
  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab, setActiveTab] = useState("personal");

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    gender: "",
    dob: "",
    maritalStatus: "",
    email: "",
    password: "",

    designation: "",
    department: "",
    salary: "",
    role: "",

    skills: "",
    customSkill: "",

    bankName: "",
    accountNumber: "",
    ifsc: "",

    qualification: "",
    university: "",
    passingYear: "",
  });

  // ---------------- Load Employee When Editing ----------------
  useEffect(() => {
    if (!isEditMode) return;

    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const found = employees.find((e) => String(e.id) === String(id));

    if (found) {
      const skillList = [
        "C","C++","Java","Advanced Java","Python",
        "NodeJS","React","Angular","MongoDB"
      ];

      const storedSkill = found.skills || "";

      setEmployee({
        ...found,
        skills: skillList.includes(storedSkill) ? storedSkill : "Other",
        customSkill: skillList.includes(storedSkill) ? "" : storedSkill
      });
    }
  }, [id, isEditMode]);

  // ---------------- Handle Change ----------------
  const handleChange = (e) => {
    setEmployee({
      ...employee,
      [e.target.name]: e.target.value,
    });
  };

  // ---------------- Final Skill Resolver ----------------
  const getFinalSkill = () => {
    return employee.skills === "Other"
      ? employee.customSkill
      : employee.skills;
  };

  // ---------------- Add Employee ----------------
  const handleAdd = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const newEmployee = {
      id: Date.now(),
      name: `${employee.firstName} ${employee.lastName}`.trim(),
      ...employee,
      skills: getFinalSkill(),
    };

    employees.push(newEmployee);
    localStorage.setItem("employees", JSON.stringify(employees));

    alert("Employee Added Successfully!");
    navigate("/dashboard/employee-details");
  };

  // ---------------- Update Employee ----------------
  const handleUpdate = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const updated = employees.map((emp) =>
      String(emp.id) === String(id)
        ? {
            ...emp,
            ...employee,
            name: `${employee.firstName} ${employee.lastName}`.trim(),
            skills: getFinalSkill(),
          }
        : emp
    );

    localStorage.setItem("employees", JSON.stringify(updated));

    alert("Employee Updated Successfully!");
    navigate("/dashboard/employee-details");
  };

  return (
    <div className="add-employee-page">
      <h2>{isEditMode ? "Edit Employee" : "Add Employee"}</h2>

      {/* ---------------- Tabs ---------------- */}
      <div className="tabs">
        <button className={`tab ${activeTab === "personal" ? "active" : ""}`} onClick={() => setActiveTab("personal")}>PERSONAL</button>
        <button className={`tab ${activeTab === "employment" ? "active" : ""}`} onClick={() => setActiveTab("employment")}>EMPLOYMENT</button>
        <button className={`tab ${activeTab === "bank" ? "active" : ""}`} onClick={() => setActiveTab("bank")}>BANK</button>
        <button className={`tab ${activeTab === "education" ? "active" : ""}`} onClick={() => setActiveTab("education")}>EDUCATION</button>
      </div>

      <form className="employee-form" onSubmit={isEditMode ? handleUpdate : handleAdd}>
        
        {/* ---------------- PERSONAL TAB ---------------- */}
        {activeTab === "personal" && (
          <>
            <h3>Personal Details</h3>
            <div className="employee-grid">

              <input name="firstName" placeholder="First Name" value={employee.firstName} onChange={handleChange} />
              <input name="lastName" placeholder="Last Name" value={employee.lastName} onChange={handleChange} />
              <input name="empId" placeholder="Employee ID" value={employee.empId} onChange={handleChange} />

              <select name="gender" value={employee.gender} onChange={handleChange}>
                <option value="">Gender</option>
                <option value="Male">Male</option>
                <option value="Female">Female</option>
              </select>

              <input type="date" name="dob" value={employee.dob} onChange={handleChange} />

              <select name="maritalStatus" value={employee.maritalStatus} onChange={handleChange}>
                <option value="">Marital Status</option>
                <option value="Single">Single</option>
                <option value="Married">Married</option>
              </select>

              <input type="email" name="email" placeholder="Email" value={employee.email} onChange={handleChange} />
              <input type="password" name="password" placeholder="Password" value={employee.password} onChange={handleChange} />
            </div>
          </>
        )}

        {/* ---------------- EMPLOYMENT TAB ---------------- */}
        {activeTab === "employment" && (
          <>
            <h3>Employment Details</h3>
            <div className="employee-grid">

              <input name="designation" placeholder="Designation" value={employee.designation} onChange={handleChange} />

              <select name="department" value={employee.department} onChange={handleChange}>
                <option value="">Select Department</option>
                <option value="Frontend">Frontend</option>
                <option value="Backend">Backend</option>
                <option value="QC (Quality Check)">QC (Quality Check)</option>
                <option value="Database">Database</option>
                <option value="IT">IT</option>
                <option value="Digital Marketing">Digital Marketing</option>
                <option value="HR">HR</option>
                <option value="Sales">Sales</option>
                <option value="USIT Recruiters">USIT Recruiters</option>
                <option value="Business Developers">Business Developers</option>
                <option value="Web Developer">Web Developer</option>
              </select>

              <input name="salary" placeholder="Salary" value={employee.salary} onChange={handleChange} />

              <select name="role" value={employee.role} onChange={handleChange}>
                <option value="">Role</option>
                <option value="Employee">Employee</option>
                <option value="Admin">Admin</option>
              </select>

              {/* ---------------- SKILLS ---------------- */}
              <select name="skills" value={employee.skills} onChange={handleChange}>
                <option value="">Select Skill</option>
                <option value="C">C</option>
                <option value="C++">C++</option>
                <option value="Java">Java</option>
                <option value="Advanced Java">Advanced Java</option>
                <option value="Python">Python</option>
                <option value="NodeJS">NodeJS</option>
                <option value="React">React</option>
                <option value="Angular">Angular</option>
                <option value="MongoDB">MongoDB</option>
                <option value="Other">Other</option>
              </select>

              {employee.skills === "Other" && (
                <input
                  name="customSkill"
                  placeholder="Enter Custom Skill"
                  value={employee.customSkill}
                  onChange={handleChange}
                />
              )}
            </div>
          </>
        )}

        {/* ---------------- BANK TAB ---------------- */}
        {activeTab === "bank" && (
          <>
            <h3>Bank Details</h3>
            <div className="employee-grid">
              <input name="bankName" placeholder="Bank Name" value={employee.bankName} onChange={handleChange} />
              <input name="accountNumber" placeholder="Account Number" value={employee.accountNumber} onChange={handleChange} />
              <input name="ifsc" placeholder="IFSC Code" value={employee.ifsc} onChange={handleChange} />
            </div>
          </>
        )}

        {/* ---------------- EDUCATION TAB ---------------- */}
        {activeTab === "education" && (
          <>
            <h3>Educational Details</h3>
            <div className="employee-grid">
              <select name="qualification" value={employee.qualification} onChange={handleChange}>
                <option value="">Highest Qualification</option>
                <option value="B.Tech">B.Tech</option>
                <option value="M.Tech">M.Tech</option>
                <option value="BSc">BSc</option>
                <option value="MBA">MBA</option>
                <option value="MCA">MCA</option>
                <option value="Diploma">Diploma</option>
              </select>

              <input name="university" placeholder="University / College" value={employee.university} onChange={handleChange} />
              <input name="passingYear" placeholder="Year of Passing" value={employee.passingYear} onChange={handleChange} />
            </div>
          </>
        )}

        <button className="save-btn" type="submit">
          {isEditMode ? "Update Employee" : "Save Employee"}
        </button>
      </form>
    </div>
  );
}

export default AddEmployee;
